var Rule = class {
	constructor() {
		_defineProperty(this, "_rules", /* @__PURE__ */ new Map());
	}
	add(key, rule) {
		this._rules.set(key, rule);
	}
	shouldBreak(codePoint, lastCodePoint, className) {
		for (const rule of this._rules.values()) if (rule(codePoint, lastCodePoint, className)) return true;
		return false;
	}
};

